var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나이엘, 장작 준비는 다 끝났어.","JPN":"ナイエル、薪は組み終わったよ。","ENG":"Naielle, the firewood's all ready.","TWN":"奈爾，木柴都準備好了。"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"으, 으응…….","JPN":"う、うん……","ENG":"O-okay...","TWN":"呃，嗯嗯……"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"내일, 캠프파이어에 점화하기 전까지는 쌓아 놓은 장작 근처에 가까이 가지 말도록 교내 방송도 마쳤습니다.","JPN":"明日の本番まで、組んだ薪に近づかないように、全校生徒には注意喚起の校内放送もしておきました。","ENG":"I've notified the student body not to go near the stacked firewood until it gets lit tomorrow.","TWN":"我也已經廣播通知大家，在明天升起營火前不要靠近堆放木柴的地方。"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"설마, 정말로 준비가 하나도 안 되어 있을 줄은 몰랐네.","JPN":"まさか、まったく準備していなかったなんて驚きだよ。","ENG":"Oh, I didn't think it was THIS unprepared.","TWN":"真是沒想到，你們竟然真的毫無準備。"},"stage":{"bg":"SPORTSGROUND","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"그래도 모두가 도와준 덕분에 어떻게든 끝낼 수 있을 것 같아.","JPN":"でも、みんなが協力したおかげで、なんとかなりそうだね。","ENG":"At least we got it done with everyone's help.","TWN":"幸好大家一起下來幫忙，總算是關關難過關關過。"},"stage":{"bg":"SPORTSGROUND","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐, 뭐야!? 누가 도와달라고 말이나 했어? 다들 이런 걸로 생색내지 말라구!","JPN":"わ、悪かったわよ……\\n","ENG":"W-what?! I didn't ask for your help! So don't rub it in, okay?","TWN":"怎，怎樣！？我有叫你們幫忙嗎？在那邊囂張什麼！"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"아무튼 남은건 점화용 토치인가. 나이엘, 토치 준비는 되었겠지?","JPN":"後は点火用のトーチだな。ナイエル、準備の方は……","ENG":"Anyway, the only thing left is the blowtorch. Naielle, did you prepare one?","TWN":"總之現在就只差點火的火把。奈爾，你有準備火把吧？"},"stage":{"bg":"SPORTSGROUND","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"토치? 아, 그게 어디 갔더라…….","JPN":"トーチ？　え？　あ、そうだった……","ENG":"A blowtorch? Oh, um, where did I put the blowtorch...","TWN":"火把？呃，那個，我放哪啦……"},"stage":{"bg":"SPORTSGROUND","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"어이, 설마 그것도 깜빡한거야?","JPN":"おいおい。それも忘れていたのか？","ENG":"You didn't forget that too, did you?","TWN":"哀，你該不會連火把都沒準備吧？"},"stage":{"bg":"SPORTSGROUND","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"괘, 괜찮아! 불을 붙이는 것 뿐이잖아? 그 정도는 간단하다구!","JPN":"だ、大丈夫！　火を点けるだけでしょ？　そんなの簡単よ！","ENG":"I-it's fine! It's just used to light the campfire, right? I can do that!","TWN":"沒，沒問題啦！不過就是點火而已，那還不簡單！"},"stage":{"bg":"SPORTSGROUND","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"나이엘씨?","JPN":"ナイエルさん？","ENG":"Naielle?","TWN":"奈爾？"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"다들 잘 봐, 마른 장작에 불 붙이는 것 정도는 이렇게!","JPN":"見てなさい。キャンプファイヤーの火ぐらいこれで！","ENG":"Look, lighting dry wood on fire is as simple as that!","TWN":"你們看好囉，在乾柴上點火，輕而易舉！"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"바보야! 지금 불을 붙이면 어떡해! 후야제는 내일 저녁에 시작한다고!","JPN":"バカ！　今、火を点けてどうする。本番は明日だぞ！","ENG":"You fool! Why would you light in on fire right now?! The post-festival party starts tomorrow!","TWN":"你這傻瓜！現在還不能點火！慶功宴是在明天晚上！"},"stage":{"bg":"SPORTSGROUND","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아…….","JPN":"あ……","ENG":"Ah...","TWN":"呃……"},"stage":{"bg":"SPORTSGROUND","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"나는 쓰레기……. 학원제 준비도 똑바로 못하고……. 불 붙이는 것도 제대로 못하는 쓰레기…….","JPN":"私はゴミ……\\n準備すらまともに出来ず、間違えて火を点けちゃうゴミ……","ENG":"I'm just garbage... I can't do anything right... I'm garbage that can't even light a fire properly...","TWN":"我這個垃圾……學園祭也準備不好……連點個火都會搞砸的垃圾……"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"불에도 안타고…… 재활용도 안 되는 멍청한 쓰레기…….","JPN":"燃えないし……リサイクルもできないバカなゴミ……","ENG":"I'm a stupid piece of garbage... that can't be burned or recycled...","TWN":"我是無法焚燒……也無法回收再利用的垃圾……"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"그렇지 않아요, 실수는 누구나 하는 거니까요.","JPN":"間違いは誰にでもありますよ、ナイエルさん。","ENG":"That's not true. Everyone makes mistakes.","TWN":"不是的，人非聖賢，誰能無過。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"그리고 나이엘 양이 누구보다 축제에 진심이라는 건 제가 가장 잘 아는 걸요.","JPN":"ナイエルさんが誰よりも学園祭に本気だったということは、\\n僕が一番わかっています。","ENG":"And I know how much you care about the festival, Naielle.","TWN":"而且我很清楚，你比任何人都還要認真看待學園祭。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"왜냐하면 나이엘 양과 마찬가지로 저도 올해 학년 대표니까요.","JPN":"ナイエルさんと同じく、僕も学年代表ですから。","ENG":"That's because, like you, I'm also this year's student representative.","TWN":"因為我和你一樣，都是今年的學生代表。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"타피르 선배…….","JPN":"タピル先輩……","ENG":"Tapir...","TWN":"達爾前輩……"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};